from __future__ import annotations
from typing import Optional


# --- Basic scalar types ---
def greet(name: str, times: int = 1) -> str:
    return ('Hello, ' + name + '! ') * times


def compute_area(width: float, height: float) -> float:
    return width * height


def is_even(n: int) -> bool:
    return n % 2 == 0


# --- None / Optional ---
# Pre-3.10 style: Optional[str] means str | None
def find_user(user_id: int) -> Optional[str]:
    users = {1: 'Alice', 2: 'Bob'}
    return users.get(user_id)  # returns str or None


# Python 3.10+ preferred union syntax
def parse_number(value: str) -> int | None:
    try:
        return int(value)
    except ValueError:
        return None


# --- Union: multiple types ---
def stringify(value: int | float | str) -> str:
    return str(value)


# --- Variable annotations ---
name: str = 'Claude'
count: int = 0
ratio: float = 0.95
flag: bool = True

# Annotation without assignment (declare type only)
result: str


# --- None return type ---
def log_message(msg: str) -> None:
    print(f'[LOG] {msg}')


# --- Demonstrating the type checker catches errors ---
# The following would be flagged by mypy/pyright:
# greet(42, 'hello')   # error: wrong argument types
# compute_area('2', 3) # error: str not assignable to float
# x: int = 'oops'     # error: str not assignable to int

from __future__ import annotations
from typing import Callable


# --- list ---
def join_words(words: list[str], sep: str = ' ') -> str:
    return sep.join(words)


def double_values(numbers: list[int]) -> list[int]:
    return [n * 2 for n in numbers]


# --- dict ---
def word_counts(text: str) -> dict[str, int]:
    counts: dict[str, int] = {}
    for word in text.lower().split():
        counts[word] = counts.get(word, 0) + 1
    return counts


def merge_configs(
    base: dict[str, str],
    overrides: dict[str, str],
) -> dict[str, str]:
    return {**base, **overrides}


# --- tuple ---
# tuple[int, str] is a 2-tuple: first element int, second str
def get_name_and_age(user_id: int) -> tuple[str, int]:
    db = {1: ('Alice', 30), 2: ('Bob', 25)}
    return db[user_id]


# tuple[int, ...] is a variable-length homogeneous tuple
def sum_scores(scores: tuple[int, ...]) -> int:
    return sum(scores)


# --- set ---
def unique_tags(posts: list[dict[str, list[str]]]) -> set[str]:
    all_tags: set[str] = set()
    for post in posts:
        all_tags.update(post.get('tags', []))
    return all_tags


# --- Callable ---
# Callable[[ArgType1, ArgType2], ReturnType]
def apply_transform(
    value: int,
    transform: Callable[[int], int],
) -> int:
    return transform(value)


result = apply_transform(5, lambda x: x * x)  # result: int = 25
print(result)
